record.field:
configs = env['ezee.optimus.fas.config'].sudo().search([('active', '=', True)])
for config in configs:
    env['ezee.optimus.sync'].with_context(fas_config_id=config.id).sudo().create({}).action_import_config()
action = {
    'type': 'ir.actions.client',
    'tag': 'display_notification',
    'params': {
        'title': 'Import Complete',
        'message': '%s active FAS configuration(s) processed.' % len(configs),
        'type': 'success',
    },
}
